from flask import Flask, request, jsonify

app = Flask(__name__)

# Basit bir middleware örneği
@app.before_request
def before_request_func():
    print("İstekten önce çalıştı.")
    # İsteği durdurmak için aşağıdaki gibi bir yanıt döndürülebilir:
    # return jsonify({'message': 'İstek engellendi.'}), 403

@app.after_request
def after_request_func(response):
    print("İstekten sonra çalıştı.")
    response.headers['X-Custom-Header'] = 'Değer'
    return response

# Hata yönetimi için middleware
@app.errorhandler(404)
def not_found_error(error):
    return jsonify({'error': 'Bulunamadı'}), 404

@app.errorhandler(500)
def internal_server_error(error):
    return jsonify({'error': 'Sunucu Hatası'}), 500

@app.route('/')
def hello_world():
    return 'Merhaba, Dünya!'

@app.route('/hata')
def hata_tetikle():
    raise Exception("Bir hata oluştu!")

if __name__ == '__main__':
    app.run(debug=True)
